import Header from "../../components/Headers/Header";
import React, { useState, useEffect } from "react";
import { Table, Button, Form, InputGroup } from "react-bootstrap";
import { FaSearch, FaEdit, FaTrash } from "react-icons/fa";
import { Link, useNavigate } from "react-router-dom";
import axios from "axios";

const ListOfDrugs = () => {
  const [drugs, setDrugs] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const navigate = useNavigate();

  // Fetch the list of drugs
  useEffect(() => {
    fetchDrugs();
  }, []);

  const fetchDrugs = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await axios.get("http://localhost:5001/api/medicine");
      setDrugs(response.data.data || []);
      console.log("List of drugs fetched:", response.data.data);
    } catch (error) {
      console.error("Error fetching drug list:", error);
      setError("Could not load the drug list. Check the server or console for details.");
    } finally {
      setLoading(false);
    }
  };

  // Handle search input
  const handleSearch = (e) => {
    setSearchTerm(e.target.value);
  };

  // Redirect to the edit page for the selected drug
  const handleEdit = (drugId) => {
    navigate(`/editDrug/${drugId}`);
  };

  // Handle drug deletion
  const handleDelete = async (id) => {
    if (window.confirm("Are you sure you want to delete this drug?")) {
      try {
        await axios.delete(`http://localhost:5001/api/medicine/${id}`);
        setDrugs((prevDrugs) => prevDrugs.filter((drug) => drug.id !== id));
        alert("Drug successfully deleted!");
      } catch (error) {
        console.error("Error deleting drug:", error);
        alert(`Failed to delete drug! Error: ${error.response?.data?.message || error.message}`);
      }
    }
  };

  // Filter drugs based on search term
  const filteredDrugs = drugs.filter(
    (drug) =>
      (drug.medicine_name &&
        drug.medicine_name.toLowerCase().includes(searchTerm.toLowerCase())) ||
      (drug.medicine_code &&
        drug.medicine_code.toLowerCase().includes(searchTerm.toLowerCase())) ||
      (drug.medicine_type_name &&
        drug.medicine_type_name.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  return (
    <>
      <Header />
      <div className="container mt-4">
        <h4 className="mb-4" style={{ fontSize: "28px", fontWeight: "bold" }}>Drug List</h4>
        {loading && <p>Loading data...</p>}
        {error && <p style={{ color: "red" }}>{error}</p>}
        {!loading && !error && (
          <>
            <div className="d-flex justify-content-between align-items-center mb-3">
              <InputGroup className="w-50">
                <Form.Control
                  placeholder="Enter name, code, or type of drug"
                  value={searchTerm}
                  onChange={handleSearch}
                />
                <Button variant="primary">
                  <FaSearch className="me-2" />
                  Search
                </Button>
              </InputGroup>
              <Link to="/addDrugForm" className="btn btn-primary">
                + Add Drug
              </Link>
            </div>
            <Table striped bordered hover>
              <thead>
                <tr>
                  <th>#</th>
                  <th>Code</th>
                  <th>Name</th>
                  <th>Type</th>
                  <th>Price (VND)</th>
                  <th>Unit</th>
                  <th>Description</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredDrugs.length > 0 ? (
                  filteredDrugs.map((drug, index) => (
                    <tr key={drug.id}>
                      <td>{index + 1}</td>
                      <td>{drug.medicine_code}</td>
                      <td>{drug.medicine_name}</td>
                      <td>{drug.medicine_type_name}</td>
                      <td>{drug.price ? drug.price.toLocaleString() : "0"}</td>
                      <td>{drug.unit}</td>
                      <td dangerouslySetInnerHTML={{ __html: drug.description }}></td>
                      <td>
                        <Button
                          variant="warning"
                          size="sm"
                          className="me-2"
                          onClick={() => handleEdit(drug.id)}
                        >
                          <FaEdit /> Edit
                        </Button>
                        <Button
                          variant="danger"
                          size="sm"
                          onClick={() => handleDelete(drug.id)}
                        >
                          <FaTrash /> Delete
                        </Button>
                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan="8" className="text-center">
                      No drugs found.
                    </td>
                  </tr>
                )}
              </tbody>
            </Table>
          </>
        )}
      </div>
    </>
  );
};

export default ListOfDrugs;
